// MARK: - User Account Manager

class UserAccountManager {
    static let shared = UserAccountManager()
    
    private let defaults = UserDefaults.standard
    
    private enum Keys {
        static let isLoggedIn = "isLoggedIn"
        static let userId = "userId"
        static let appliedPromoCode = "appliedPromoCode"
        static let appliedDiscount = "appliedDiscount"
        static let usedPromoCodes = "usedPromoCodes"
    }
    
    var isLoggedIn: Bool {
        get { defaults.bool(forKey: Keys.isLoggedIn) }
        set { defaults.set(newValue, forKey: Keys.isLoggedIn) }
    }
    
    var userId: String? {
        get { defaults.string(forKey: Keys.userId) }
        set { defaults.set(newValue, forKey: Keys.userId) }
    }
    
    var currentAppliedPromoCode: String? {
        get { defaults.string(forKey: Keys.appliedPromoCode) }
        set { defaults.set(newValue, forKey: Keys.appliedPromoCode) }
    }
    
    var currentAppliedDiscount: Int {
        get { defaults.integer(forKey: Keys.appliedDiscount) }
        set { defaults.set(newValue, forKey: Keys.appliedDiscount) }
    }
    
    var usedPromoCodes: [String] {
        get { defaults.stringArray(forKey: Keys.usedPromoCodes) ?? [] }
        set { defaults.set(newValue, forKey: Keys.usedPromoCodes) }
    }
    
    private init() {}
    
    func hasUsedPromoCode(_ code: String) -> Bool {
        return usedPromoCodes.contains(code.uppercased())
    }
    
    func markPromoCodeAsUsed(_ code: String) {
        var codes = usedPromoCodes
        codes.append(code.uppercased())
        usedPromoCodes = codes
    }
    
    func applyPromoToAccount(code: String, discount: Int) {
        currentAppliedPromoCode = code.uppercased()
        currentAppliedDiscount = discount
        markPromoCodeAsUsed(code)
    }
    
    func removeAppliedPromo() {
        currentAppliedPromoCode = nil
        currentAppliedDiscount = 0
    }
}

// MARK: - Promo Link Handler

class PromoLinkHandler {
    static let shared = PromoLinkHandler()
    
    private let supportedHost = "myapp.com"
    private let promoPath = "/promo"
    
    private var pendingPromoCode: String?
    private var pendingDiscount: Int?
    
    private init() {}
    
    // MARK: - URL Parsing
    
    func canHandleURL(_ url: URL) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return false
        }
        return components.host == supportedHost && components.path == promoPath
    }
    
    func extractPromoParameters(from url: URL) -> (code: String?, discount: Int?) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return (nil, nil)
        }
        
        let queryItems = components.queryItems ?? []
        
        let code = queryItems.first(where: { $0.name == "code" })?.value
        let discountString = queryItems.first(where: { $0.name == "discount" })?.value
        let discount = discountString.flatMap { Int($0) }
        
        return (code, discount)
    }
    
    // MARK: - Handle Universal Link
    
    func handleUniversalLink(_ url: URL, completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void) {
        guard canHandleURL(url) else {
            completion(.failure(.invalidCode))
            return
        }
        
        let params = extractPromoParameters(from: url)
        
        guard let code = params.code, !code.isEmpty else {
            completion(.failure(.invalidCode))
            return
        }
        
        guard let discount = params.discount, discount > 0, discount <= 100 else {
            completion(.failure(.invalidDiscount))
            return
        }
        
        let accountManager = UserAccountManager.shared
        
        guard accountManager.isLoggedIn else {
            // Store pending promo for after login
            pendingPromoCode = code
            pendingDiscount = discount
            completion(.failure(.userNotLoggedIn))
            return
        }
        
        applyPromoCode(code: code, discount: discount, completion: completion)
    }
    
    // MARK: - Apply Promo Code
    
    func applyPromoCode(code: String, discount: Int, completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void) {
        let accountManager = UserAccountManager.shared
        
        // Validate discount range
        guard discount > 0 && discount <= 100 else {
            completion(.failure(.invalidDiscount))
            return
        }
        
        // Check if user already used this code
        guard !accountManager.hasUsedPromoCode(code) else {
            completion(.failure(.alreadyUsed))
            return
        }
        
        // Check if a promo is already applied
        guard accountManager.currentAppliedPromoCode == nil else {
            completion(.failure(.codeAlreadyApplied))
            return
        }
        
        // Validate with server
        validatePromoCodeWithServer(code: code, discount: discount) { result in
            switch result {
            case .success(let promoCode):
                guard promoCode.isValid else {
                    completion(.failure(.invalidCode))
                    return
                }
                
                guard !promoCode.isExpired else {
                    completion(.failure(.expiredCode))
                    return
                }
                
                guard !promoCode.hasReachedMaxUsage else {
                    completion(.failure(.maxUsageReached))
                    return
                }
                
                // Apply the promo code
                accountManager.applyPromoToAccount(code: code, discount: discount)
                
                let result = PromoApplicationResult(
                    success: true,
                    message: "Promo code \(code.uppercased()) applied! You get \(discount)% off!",
                    appliedDiscount: discount,
                    promoCode: code.uppercased()
                )
                completion(.success(result))
                
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    // MARK: - Server Validation (Simulated)
    
    private func validatePromoCodeWithServer(code: String, discount: Int, completion: @escaping (Result<PromoCode, PromoError>) -> Void) {
        // Simulate network request
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) {
            // In production, this would be a real API call
            let promoCode = PromoCode(
                code: code.uppercased(),
                discountPercentage: discount,
                isValid: true,
                expirationDate: Calendar.current.date(byAdding: .month, value: 1, to: Date()),
                minimumPurchaseAmount: nil,
                maxUsageCount: 1000,
                currentUsageCount: 50
            )
            
            DispatchQueue.main.async {
                completion(.success(promoCode))
            }
        }
    }
    
    // MARK: - Pending Promo (for after login)
    
    func hasPendingPromo() -> Bool {
        return pendingPromoCode != nil && pendingDiscount != nil
    }
    
    func applyPendingPromo(completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void) {
        guard let code = pendingPromoCode, let discount = pendingDiscount else {
            completion(.failure(.invalidCode))
            return
        }
        
        pendingPromoCode = nil
        pendingDiscount = nil
        
        applyPromoCode(code: code, discount: discount, completion: completion)
    }
    
    func clearPendingPromo() {
        pendingPromoCode = nil
        pendingDiscount = nil
    }
}

